const baseConfig = $('Config Reporte').first().json;
const triggerConfig = $('SetTrigger - Flujo').first()?.json || {};
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}

function scalarText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = String(value).trim();
    return text === '[object Object]' ? '' : text;
  }
  return '';
}

function cleanContactText(value) {
  let text = scalarText(value);
  if (!text) return '';
  if (text.includes(' / ')) text = text.split(' / ')[0].trim();
  return text;
}

function normalizeContactEntry(entry) {
  if (entry === undefined || entry === null) return '';
  const direct = cleanContactText(entry);
  if (direct) return direct;
  if (Array.isArray(entry)) return entry.map(normalizeContactEntry).filter(Boolean).join(', ');
  if (typeof entry === 'object') {
    if (entry.fields && typeof entry.fields === 'object') {
      const fromFields = normalizeContactEntry(entry.fields);
      if (fromFields) return fromFields;
    }
    if (entry.objects && typeof entry.objects === 'object') {
      return Object.values(entry.objects).map(normalizeContactEntry).filter(Boolean).join(', ');
    }
    const preferred = ['contact_id_friendlyname','person_id_friendlyname','user_id_friendlyname','contact_name','person_name','display_name','name','friendlyname','email','email_address'];
    for (const field of preferred) {
      const text = cleanContactText(entry[field]);
      if (text) return text;
    }
    const nested = ['contact_id','person_id','user_id','contact','person','user'];
    for (const field of nested) {
      const text = normalizeContactEntry(entry[field]);
      if (text) return text;
    }
  }
  return '';
}

function normalizeContacts(value) {
  const text = normalizeContactEntry(value);
  if (!text) return '';
  const unique = [];
  const seen = new Set();
  for (const part of text.split(',').map(v => cleanContactText(v)).filter(Boolean)) {
    const key = part.toLowerCase();
    if (!seen.has(key)) { seen.add(key); unique.push(part); }
  }
  return unique.join(', ');
}

function isBlankValue(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'n/a' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined' || v.toLowerCase() === 'sin bodega/localidad';
}

function inferWorkstationClass(f) {
  const rawHints = [
    getField(f, ['finalclass', 'class', 'class_friendlyname'], ''),
    getField(f, ['type', 'type_friendlyname', 'computer_type', 'computer_type_friendlyname', 'device_type', 'device_type_friendlyname'], ''),
    getField(f, ['category', 'category_friendlyname', 'subcategory', 'subcategory_friendlyname'], ''),
    getField(f, ['name', 'friendlyname'], ''),
    getField(f, ['model_id_friendlyname', 'model'], ''),
    getField(f, ['brand_id_friendlyname', 'brand'], ''),
    getField(f, ['description', 'comment', 'comments'], ''),
  ].map(v => String(v || '').trim()).filter(Boolean);
  const hint = rawHints.join(' ').toLowerCase();
  const laptopPatterns = ['laptop','notebook','portable','portatil','portátil','ultrabook','latitude','elitebook','probook','thinkpad','thinkbook','macbook','vivobook','zenbook','travelmate','tecra','xps 13','xps 15',/\b(34|35|54|55|72|73|74|75)[0-9]{2}\b/,/\bt14\b/,/\bt15\b/,/\bx1\b/,/\be14\b/,/\be15\b/];
  const desktopPatterns = ['desktop','sobremesa','escritorio','tower','torre','sff','micro','minitower','optiplex','prodesk','elitedesk','thinkcentre','workstation','all-in-one','all in one','aio'];
  for (const pattern of desktopPatterns) if (hint.includes(pattern)) return 'PC';
  for (const pattern of laptopPatterns) if (pattern instanceof RegExp ? pattern.test(hint) : hint.includes(pattern)) return 'Laptop';
  return 'PC';
}

function normalizeClass(value, f = {}) {
  const raw = String(value || '-').trim();
  const lower = raw.toLowerCase();
  if (lower === 'pc' || lower === 'pc/laptop' || lower.includes('pc/laptop') || lower.includes('desktop') || lower.includes('laptop') || lower.includes('notebook') || lower.includes('portable')) {
    return inferWorkstationClass({ ...f, finalclass: raw });
  }
  if (lower === 'mobilephone' || lower.includes('phone') || lower.includes('telefono') || lower.includes('teléfono')) return 'Teléfonos móviles';
  if (lower === 'tablet') return 'Tablets';
  if (lower === 'printer' || lower.includes('impresora')) return 'Impresoras';
  if (lower === 'peripheral' || lower.includes('periferico') || lower.includes('periférico')) return 'Periféricos';
  return raw || 'Otros';
}

function classSortWeight(className) {
  const order = { 'PC': 10, 'Laptop': 20, 'Tablets': 30, 'Teléfonos móviles': 40, 'Impresoras': 50, 'Periféricos': 60, 'Otros': 90 };
  return order[className] || 80;
}

function normalizeStatusInfo(value) {
  const raw = String(value || '-').trim();
  const s = raw.toLowerCase();
  if (s === 'stock' || s.includes('stock') || s.includes('inventario') || s.includes('available') || s.includes('disponible')) return { key: 'stock', label: 'En Inventario', raw };
  if (s === 'implementation' || s.includes('implementation') || s.includes('implementacion') || s.includes('implementación') || s.includes('no productivo')) return { key: 'implementation', label: 'No Productivo', raw };
  if (s === 'production' || s.includes('production') || s.includes('produccion') || s.includes('producción') || s.includes('active') || s.includes('assigned') || s.includes('asignado')) return { key: 'production', label: 'Productivo', raw };
  if (s === 'obsolete' || s.includes('obsolete') || s.includes('obsoleto') || s.includes('retired') || s.includes('retirado')) return { key: 'obsolete', label: 'Obsoleto', raw };
  return { key: 'other', label: raw || 'Sin estado', raw };
}

function statusSortWeight(key) { return ({ stock: 10, implementation: 20, production: 30, obsolete: 40, other: 90 })[key] || 99; }
function badge(text, cls='badge-gray') { return `<span class="badge ${cls}">${escapeHtml(text)}</span>`; }
function statusBadgeByKey(key, label) {
  if (key === 'production') return badge(label, 'badge-green');
  if (key === 'stock') return badge(label, 'badge-blue');
  if (key === 'implementation') return badge(label, 'badge-orange');
  if (key === 'obsolete') return badge(label, 'badge-gray');
  return badge(label, 'badge-yellow');
}
function td(value, align='left') { return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`; }
function th(value, align='left') { return `<th align="${align}" style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:${align}; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(value)}</th>`; }
function fmtDateOnly(value) {
  if (!value || value === '-') return '-';
  const d = new Date(String(value).replace(' ', 'T'));
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString('es-CL', { timeZone: config.timezone || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit' });
}

const generatedAt = new Date().toLocaleString('es-CL', { timeZone: config.timezone || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
const rawRows = flattenInput($input.all());

const mappedAssets = rawRows.map((row) => {
  const f = row.fields || row;
  const contactRaw = getField(f, ['contacts_list_friendlyname','contacts_list','contact_id_friendlyname','contact_name','person_id_friendlyname','user_id_friendlyname'], '');
  const statusInfo = normalizeStatusInfo(getField(f, ['operational_status_friendlyname','operational_status','status_friendlyname','status'], '-'));
  const finalclassRaw = getField(f, ['finalclass','class','class_friendlyname'], '-');
  return {
    id: getField(f, ['id','key'], ''),
    name: getField(f, ['name','friendlyname'], '-'),
    finalclass: normalizeClass(finalclassRaw, f),
    finalclassRaw,
    status: statusInfo.label,
    statusKey: statusInfo.key,
    statusRaw: statusInfo.raw,
    organization: getField(f, ['org_id_friendlyname','organization_name','org_name'], '-'),
    location: getField(f, ['location_id_friendlyname','location_name','location_id'], ''),
    contacts: normalizeContacts(contactRaw),
    brand: getField(f, ['brand_id_friendlyname','brand'], '-'),
    model: getField(f, ['model_id_friendlyname','model'], '-'),
    serial: getField(f, ['serialnumber','serial_number'], ''),
    move2production: getField(f, ['move2production','production_date'], '-'),
    purchaseDate: getField(f, ['purchase_date'], '-'),
    warrantyEnd: getField(f, ['end_of_warranty'], '-'),
  };
});

const unique = new Map();
for (const a of mappedAssets) {
  const key = String(a.id || `${a.finalclass}|${a.name}|${a.serial}`);
  if (!unique.has(key)) unique.set(key, a);
}

for (const asset of unique.values()) {
  if (String(asset.finalclass || '').trim().toLowerCase() === 'pc/laptop') {
    asset.finalclass = 'PC';
  }
}

const assets = Array.from(unique.values()).sort((a,b) =>
  statusSortWeight(a.statusKey) - statusSortWeight(b.statusKey) ||
  classSortWeight(a.finalclass) - classSortWeight(b.finalclass) ||
  String(a.finalclass).localeCompare(String(b.finalclass),'es') ||
  String(a.location).localeCompare(String(b.location),'es') ||
  String(a.name).localeCompare(String(b.name),'es')
);

function isProductionStatus(a) { return a.statusKey === 'production'; }
function isStockStatus(a) { return a.statusKey === 'stock'; }
function isImplementationStatus(a) { return a.statusKey === 'implementation'; }
function isObsoleteStatus(a) { return a.statusKey === 'obsolete'; }

const classes = new Map(), classStatus = new Map(), classLocation = new Map(), locations = new Map();
function inc(map, key, by=1) { map.set(key, (map.get(key) || 0) + by); }

for (const a of assets) {
  if (!classes.has(a.finalclass)) classes.set(a.finalclass, []);
  classes.get(a.finalclass).push(a);
  inc(classStatus, `${a.finalclass}||${a.statusKey}||${a.status}`);
  inc(classLocation, `${a.finalclass}||${a.location || 'Sin bodega/localidad'}`);
  const loc = a.location || 'Sin bodega/localidad';
  if (!locations.has(loc)) locations.set(loc, []);
  locations.get(loc).push(a);
}

const classSummaryRows = Array.from(classes.entries())
  .sort(([a],[b]) => classSortWeight(a) - classSortWeight(b) || a.localeCompare(b,'es'))
  .map(([cls, list]) => `<tr>` +
    td(escapeHtml(cls)) +
    td(`<strong>${list.length}</strong>`,'right') +
    td(list.filter(isProductionStatus).length,'right') +
    td(list.filter(isStockStatus).length,'right') +
    td(list.filter(a => isImplementationStatus(a) || isObsoleteStatus(a)).length,'right') +
    td(list.filter(a => !String(a.location || '').trim()).length,'right') +
  `</tr>`).join('');

const classStatusRows = Array.from(classStatus.entries()).sort((a,b) => {
  const [classA, keyA] = a[0].split('||');
  const [classB, keyB] = b[0].split('||');
  return classSortWeight(classA) - classSortWeight(classB) || classA.localeCompare(classB,'es') || statusSortWeight(keyA) - statusSortWeight(keyB);
}).map(([key,count]) => {
  const [cls,statusKey,statusLabel]=key.split('||');
  const obs = statusKey === 'implementation' ? badge('No productivo / implementación','badge-orange') : statusKey === 'obsolete' ? badge('Fuera de ciclo','badge-gray') : statusKey === 'stock' ? badge('Disponible en inventario','badge-blue') : statusKey === 'production' ? badge('Activo operativo','badge-green') : badge('Validar estado','badge-yellow');
  return `<tr>` + td(escapeHtml(cls)) + td(statusBadgeByKey(statusKey, statusLabel)) + td(`<strong>${count}</strong>`,'right') + td(obs) + `</tr>`;
}).join('');

const orderedMatrixClasses = Array.from(classes.keys())
  .sort((a,b) => classSortWeight(a) - classSortWeight(b) || a.localeCompare(b,'es'));

const locationMatrixHeaderCells = [
  th('Bodega / localidad'),
  th('Estado'),
  ...orderedMatrixClasses.map(cls => th(cls, 'right')),
  th('Total', 'right'),
].join('');

const locationMatrixRows = Array.from(locations.entries())
  .sort(([a],[b]) => a.localeCompare(b,'es'))
  .map(([loc, list]) => {
    const statusMap = new Map();
    for (const asset of list) {
      if (!statusMap.has(asset.statusKey)) {
        statusMap.set(asset.statusKey, { key: asset.statusKey, label: asset.status, list: [] });
      }
      statusMap.get(asset.statusKey).list.push(asset);
    }

    return Array.from(statusMap.values())
      .sort((a,b) => statusSortWeight(a.key) - statusSortWeight(b.key) || a.label.localeCompare(b.label,'es'))
      .map(({ key: statusKey, label: statusLabel, list: statusList }) => {
        const classCells = orderedMatrixClasses.map((cls) => {
          const count = statusList.filter(asset => asset.finalclass === cls).length;
          return td(count ? `<strong>${count}</strong>` : '0', 'right');
        }).join('');

        return `<tr>` +
          td(escapeHtml(loc || 'Sin bodega/localidad')) +
          td(statusBadgeByKey(statusKey, statusLabel)) +
          classCells +
          td(`<strong>${statusList.length}</strong>`, 'right') +
        `</tr>`;
      }).join('');
  }).join('');

const topLocationRows = Array.from(locations.entries()).sort((a,b)=>b[1].length-a[1].length).map(([loc,list]) => {
  const classNames=[...new Set(list.map(a=>a.finalclass))].sort((a,b)=>classSortWeight(a)-classSortWeight(b)||a.localeCompare(b,'es')).join(', ');
  return `<tr>` + td(escapeHtml(loc)) + td(`<strong>${list.length}</strong>`,'right') + td(escapeHtml(classNames || '-')) + `</tr>`;
}).join('');

const csvHeaders = [
  'Nombre', 'Clase/Tipo', 'Estado', 'Bodega/Localidad', 'Contactos', 'Marca', 'Modelo', 'Serie', 'Puesto en Produccion', 'Fecha de Compra', 'Vencimiento de Garantia'
];
const csvRows = assets.map(a => [a.name, a.finalclass, a.status, a.location || 'Sin bodega/localidad', a.contacts, a.brand, a.model, a.serial, fmtDateOnly(a.move2production), fmtDateOnly(a.purchaseDate), fmtDateOnly(a.warrantyEnd)]);
const csvContent = '\uFEFF' + [csvHeaders.map(csvEscape).join(';'), ...csvRows.map(row => row.map(csvEscape).join(';'))].join('\r\n');

const subjectBase = String(config.email_subject || 'Reporte CMDB - resumen por clase, estado y bodega').trim();
const emailSubject = itopOrganization ? `${subjectBase} - ${itopOrganization}` : subjectBase;
const generatedAtFile = new Date().toISOString().replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);

return [{
  json: {
    flags: config.flags || {},
    include_attachment: config.flags?.include_attachment ?? config.include_attachment,
    include_detail: config.flags?.include_detail ?? config.include_detail,
    include_summary: config.flags?.include_summary ?? config.include_summary,
    include_operational_notes: config.flags?.include_operational_notes ?? config.include_operational_notes,
    include_itop_button_footer: config.flags?.include_itop_button_footer ?? config.include_itop_button_footer,
    email_from: config.email_from,
    email_to: config.email_to,
    email_cc: config.email_cc || '',
    email_bcc: config.email_bcc || '',
    email_subject: emailSubject,
    company,
    Company: company,
    itop_organization: itopOrganization || '-',
    generated_at: generatedAt,
    total_assets: String(assets.length),
    production_count: String(assets.filter(isProductionStatus).length),
    stock_count: String(assets.filter(isStockStatus).length),
    without_location_count: String(assets.filter(a => !String(a.location || '').trim()).length),
    non_operational_count: String(assets.filter(a => isImplementationStatus(a) || isObsoleteStatus(a)).length),
    implementation_count: String(assets.filter(isImplementationStatus).length),
    obsolete_count: String(assets.filter(isObsoleteStatus).length),
    class_count: String(classes.size),
    class_summary_rows: classSummaryRows || `<tr>${td('Sin datos CMDB para resumir.')}</tr>`,
    class_status_rows: classStatusRows || `<tr>${td('Sin estados para resumir.')}</tr>`,
    location_matrix_header_cells: locationMatrixHeaderCells,
    location_matrix_rows: locationMatrixRows || `<tr><td colspan="${orderedMatrixClasses.length + 3}" style="padding:12px; font-size:12px; color:#64748b;">Sin bodegas/localidades para resumir.</td></tr>`,
    top_location_rows: topLocationRows || `<tr>${td('Sin bodegas/localidades para listar.')}</tr>`,
    itop_url: config.itop_url || '#',
    csv_filename: `cmdb_resumen_clase_estado_bodega_${generatedAtFile}.csv`,
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: `cmdb_resumen_clase_estado_bodega_${generatedAtFile}.csv`,
    },
  },
}];

const input = $input.first();
const data = input.json || {};

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}



function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function flagEnabled(name, fallback = true) {
  const trigger = getNodeJson('SetTrigger - Flujo');
  const mixed = getNodeJson('SetMixed - Configuracion efectiva');
  const value = trigger[name] ?? trigger.flags?.[name] ?? data[name] ?? data.flags?.[name] ?? mixed[name] ?? mixed.flags?.[name];
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function removeOuterRowByMarker(html, marker) {
  let index = html.indexOf(marker);
  if (index === -1) return html;
  const starts = ['\n      <tr><td', '\n                        <tr><td', '\n                        <tr><td align', '\n      <tr><td align'];
  let start = -1;
  for (const token of starts) {
    const candidate = html.lastIndexOf(token, index);
    if (candidate > start) start = candidate;
  }
  if (start === -1) start = html.lastIndexOf('<tr><td', index);
  if (start === -1) return html;
  let end = html.indexOf('\n\n      <tr><td', index);
  const endAlt = html.indexOf('\n\n                        <tr><td', index);
  if (end === -1 || (endAlt !== -1 && endAlt < end)) end = endAlt;
  const footerAlt = html.indexOf('\n      <tr><td style="background-color', index);
  if (end === -1 || (footerAlt !== -1 && footerAlt < end)) end = footerAlt;
  const footerAlt2 = html.indexOf('\n                        <tr><td style="background-color', index);
  if (end === -1 || (footerAlt2 !== -1 && footerAlt2 < end)) end = footerAlt2;
  if (end === -1) {
    const close = html.indexOf('</td></tr>', index);
    if (close === -1) return html;
    end = close + '</td></tr>'.length;
  }
  return html.slice(0, start) + html.slice(end);
}

function removeNextOuterRowAfterMarker(html, marker) {
  const index = html.indexOf(marker);
  if (index === -1) return html;
  const firstEnd = html.indexOf('\n\n      <tr><td', index);
  const firstEndAlt = html.indexOf('\n\n                        <tr><td', index);
  let start = firstEnd;
  if (start === -1 || (firstEndAlt !== -1 && firstEndAlt < start)) start = firstEndAlt;
  if (start === -1) return html;
  let end = html.indexOf('\n\n      <tr><td', start + 1);
  const endAlt = html.indexOf('\n\n                        <tr><td', start + 1);
  if (end === -1 || (endAlt !== -1 && endAlt < end)) end = endAlt;
  if (end === -1) return html;
  return html.slice(0, start) + html.slice(end);
}

function applyVisualFlags(html) {
  if (!flagEnabled('include_summary')) {
    html = removeNextOuterRowAfterMarker(html, 'Resumen ejecutivo');
    html = removeOuterRowByMarker(html, 'Resumen ejecutivo');
  }
  if (!flagEnabled('include_detail')) {
    for (const marker of [
      'Detalle operacional',
      'Tickets abiertos pendientes',
      'Tickets abiertos por agente',
      'Tickets con más de 14 días abiertos',
      'Tickets abiertos hasta 14 días',
      'older_section',
      'recent_section',
      'ticket_sections',
      'data-table',
      'ticket-table'
    ]) {
      let previous;
      do {
        previous = html;
        html = removeOuterRowByMarker(html, marker);
      } while (html !== previous);
    }
  }
  if (!flagEnabled('include_operational_notes')) {
    html = removeOuterRowByMarker(html, 'Observaciones operacionales');
  }
  if (!flagEnabled('include_itop_button_footer')) {
    html = removeOuterRowByMarker(html, 'Abrir Combodo iTop');
  }
  return html;
}

const template = `<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Resumen CMDB por clase, estado y bodega</title>
  <style type="text/css">
    body { margin:0; padding:0; background-color:#eef2f6; font-family:Arial, Helvetica, sans-serif; color:#1f2937; }
    table { border-collapse:collapse; }
    a { color:#1d4ed8; text-decoration:none; }
    .wrapper { width:100%; background-color:#eef2f6; padding:24px 0; }
    .container { width:100%; max-width:1000px; background-color:#ffffff; border:1px solid #d9e2ec; }
