const base = $input.first()?.json || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};

function normalizeBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si'].includes(text)) return true;
  if (['false', '0', 'no', 'n'].includes(text)) return false;
  return fallback;
}

const flags = { ...(base.flags || {}) };
for (const key of ['include_attachment', 'include_detail', 'include_summary', 'include_operational_notes', 'include_itop_button_footer', 'send_email', 'include_requirements', 'include_incidents', 'include_changes', 'include_problems']) {
  if (trigger[key] !== undefined && trigger[key] !== null && trigger[key] !== '') {
    flags[key] = normalizeBoolean(trigger[key], flags[key]);
  }
}

const setMixed = {
  ...base,
  ...trigger,
  flags,
  config_source: 'SetBase + SetTrigger',
};

for (const [key, value] of Object.entries(flags)) {
  if (setMixed[key] === undefined || setMixed[key] === null || setMixed[key] === '') setMixed[key] = value;
}

return [{ json: setMixed }];

function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function mergeFlags(...sources) {
  const flags = {};
  for (const source of sources) {
    if (!source) continue;
    Object.assign(flags, source.flags || {});
    for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) {
      if (source[key] !== undefined && source[key] !== null && source[key] !== '') flags[key] = normalizeBoolean(source[key], flags[key]);
    }
  }
  return flags;
}

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function flagEnabled(data, name, fallback = true) {
  return normalizeBoolean(data[name] ?? data.flags?.[name], fallback);
}

function removeOuterRowByMarker(html, marker) {
  const index = html.indexOf(marker);
  if (index === -1) return html;
  const starts = ['\n      <tr><td', '\n                        <tr><td', '<tr><td', '<tr>'];
  let start = -1;
  for (const needle of starts) {
    const pos = html.lastIndexOf(needle, index);
    if (pos !== -1 && pos > start) start = pos;
  }
  if (start === -1) start = Math.max(0, index - 200);
  const ends = ['\n      <tr><td', '\n                        <tr><td', '\n      <tr><td style="background-color', '\n                        <tr><td style="background-color'];
  let end = -1;
  for (const needle of ends) {
    const pos = html.indexOf(needle, index + marker.length);
    if (pos !== -1 && (end === -1 || pos < end)) end = pos;
  }
  if (end === -1) {
    const close = html.indexOf('</td></tr>', index);
    end = close === -1 ? index + marker.length : close + '</td></tr>'.length;
  }
  return html.slice(0, start) + html.slice(end);
}

function removeAllRowsByMarker(html, marker) {
  let previous;
  do {
    previous = html;
    html = removeOuterRowByMarker(html, marker);
  } while (html !== previous);
  return html;
}

function removeTablesByClass(html) {
  return html
    .replace(/<table\b[^>]*class=["'][^"']*(?:data-table|ticket-table)[^"']*["'][\s\S]*?<\/table>/gi, '')
    .replace(/<table\b[^>]*(?:data-table|ticket-table)[^>]*>[\s\S]*?<\/table>/gi, '');
}

function applyVisualFlags(html, data) {
  if (!html) return html;
  if (!flagEnabled(data, 'include_summary', true)) {
    for (const marker of ['Resumen ejecutivo', 'TOTAL ACTIVOS', 'TOTAL CON CONTACTO', 'TOTAL TICKETS', 'TOTAL CAMBIOS', 'TOTAL MOVIMIENTOS']) html = removeAllRowsByMarker(html, marker);
  }
  if (!flagEnabled(data, 'include_detail', true)) {
    for (const marker of [
      'Detalle operacional',
      'Detalle de activos',
      'Detalle de tickets',
      'Detalle por agente',
      'Detalle por antig?edad',
      'Resumen por estado',
      'Resumen por bodega/localidad',
      'Resumen por clase',
      'Activos por clase',
      'Por revisar',
      'Tickets abiertos',
      'Tickets abiertos pendientes',
      'Tickets abiertos por agente',
      'Tickets con m?s de 14 d?as abiertos',
      'Tickets abiertos hasta 14 d?as',
      'Movimientos recientes',
      'data-table',
      'ticket-table'
    ]) html = removeAllRowsByMarker(html, marker);
    html = removeTablesByClass(html);
    html = html.replace(/\.data-table[\s\S]*?\}/g, '').replace(/\.ticket-table[\s\S]*?\}/g, '');
  }
  if (!flagEnabled(data, 'include_operational_notes', true)) html = removeAllRowsByMarker(html, 'Observaciones operacionales');
  if (!flagEnabled(data, 'include_itop_button_footer', true)) html = removeAllRowsByMarker(html, 'Abrir Combodo iTop');
  return html;
}

return $input.all().map((item) => {
  const configReporte = getNodeJson('Config Reporte');
  const setMixed = getNodeJson('SetMixed - Configuracion efectiva');
  const setTrigger = getNodeJson('SetTrigger - Flujo');
  const itemJson = item.json || {};
  const flags = mergeFlags(configReporte, setMixed, itemJson, setTrigger);
  const data = { ...configReporte, ...setMixed, ...itemJson, ...setTrigger, flags };
  for (const [key, value] of Object.entries(flags)) data[key] = value;

  const includeAttachment = flagEnabled(data, 'include_attachment', true);
  const binary = includeAttachment ? (item.binary || {}) : {};
  const html = applyVisualFlags(data.html, data);

  return {
    json: {
      ...data,
      html,
      include_attachment_effective: includeAttachment,
      attachment_binary_names: includeAttachment && binary.csv ? 'csv' : '',
      has_csv_binary: Boolean(binary.csv),
    },
    binary,
  };
});

const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}

function positiveNumber(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return false;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0;
}

function validDateText(name) {
  const value = text(name);
  if (!value) return false;
  const parsed = new Date(value.replace(' ', 'T'));
  return !Number.isNaN(parsed.getTime());
}

function dateWindowState() {
  const hasStart = text('start_date').length > 0;
  const hasEnd = text('end_date').length > 0;
  if (!hasStart && !hasEnd) return { provided: false, valid: false };
  if (!hasStart || !hasEnd) return { provided: true, valid: false, error: 'start_date y end_date deben enviarse juntos.' };
  if (!validDateText('start_date') || !validDateText('end_date')) return { provided: true, valid: false, error: 'start_date y end_date deben ser fechas validas.' };
  const start = new Date(text('start_date').replace(' ', 'T'));
  const end = new Date(text('end_date').replace(' ', 'T'));
  if (start > end) return { provided: true, valid: false, error: 'start_date no puede ser mayor que end_date.' };
  return { provided: true, valid: true };
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

const webhookPath = 'cmdb-resumen-clase-estado-bodega';
const window = dateWindowState();

if (webhookPath === 'cmdb-movimientos-recientes-inventario') {
  const hasMovementDays = positiveNumber('movement_days');
  if (!hasMovementDays && !window.valid) {
    errors.push(window.error || 'Debe enviar movement_days positivo o la ventana start_date + end_date.');
  }
}

if (webhookPath === 'cmdb-activos-proximos-vencer-garantia') {
  if (!positiveNumber('warranty_warning_months')) {
    errors.push('warranty_warning_months es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (webhookPath === 'itsm-tickets-sin-actualizacion-24h') {
  if (!positiveNumber('stale_threshold_hours')) {
    errors.push('stale_threshold_hours es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (window.provided && !window.valid && webhookPath !== 'cmdb-movimientos-recientes-inventario') {
  errors.push(window.error || 'Ventana de fechas invalida.');
}

const valid = errors.length === 0;

return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

const item = $input.first();
const json = item?.json || {};

if (!json.webhook_contract?.valid) {
  return [];
}

const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];
